// AccountAdminServiceHandler is an implementation of the platform.v1.AccountAdminService service.
type AccountAdminServiceHandler interface {
	// ProvisionAccount creates a human user account.
	ProvisionAccount(context.Context, *connect.Request[v1.ProvisionAccountRequest]) (*connect.Response[v1.ProvisionAccountResponse], error)
	// ProvisionServiceAccount creates a service_account or workload_identity
	// with an optional or required expires_at lifetime.
	ProvisionServiceAccount(context.Context, *connect.Request[v1.ProvisionServiceAccountRequest]) (*connect.Response[v1.ProvisionServiceAccountResponse], error)
	// GetAccount retrieves a single account by id within the tenant.
	GetAccount(context.Context, *connect.Request[v1.GetAccountRequest]) (*connect.Response[v1.GetAccountResponse], error)
	// ListAccounts returns a paginated list of accounts in the tenant.
	ListAccounts(context.Context, *connect.Request[v1.ListAccountsRequest]) (*connect.Response[v1.ListAccountsResponse], error)
	// UpdateAccount mutates non-lifecycle attributes (display_name, email,
	// org_affiliation, clearance). Status transitions go through
	// Suspend/Recover/Deprovision.
	UpdateAccount(context.Context, *connect.Request[v1.UpdateAccountRequest]) (*connect.Response[v1.UpdateAccountResponse], error)
	// SuspendAccount transitions the account to "suspended". Attributes retained.
	SuspendAccount(context.Context, *connect.Request[v1.SuspendAccountRequest]) (*connect.Response[v1.SuspendAccountResponse], error)
	// RecoverAccount transitions a suspended account back to "active".
	RecoverAccount(context.Context, *connect.Request[v1.RecoverAccountRequest]) (*connect.Response[v1.RecoverAccountResponse], error)
	// DeprovisionAccount transitions the account to "deleted" (soft delete).
	DeprovisionAccount(context.Context, *connect.Request[v1.DeprovisionAccountRequest]) (*connect.Response[v1.DeprovisionAccountResponse], error)
	// DefineGroup creates a tenant-scoped group.
	DefineGroup(context.Context, *connect.Request[v1.DefineGroupRequest]) (*connect.Response[v1.DefineGroupResponse], error)
	// ListGroups returns groups in the tenant.
	ListGroups(context.Context, *connect.Request[v1.ListGroupsRequest]) (*connect.Response[v1.ListGroupsResponse], error)
	// AddAccountToGroup adds an account to a group.
	AddAccountToGroup(context.Context, *connect.Request[v1.AddAccountToGroupRequest]) (*connect.Response[v1.AddAccountToGroupResponse], error)
	// RemoveAccountFromGroup removes an account from a group.
	RemoveAccountFromGroup(context.Context, *connect.Request[v1.RemoveAccountFromGroupRequest]) (*connect.Response[v1.RemoveAccountFromGroupResponse], error)
	// DefineRole creates a tenant-scoped role.
	DefineRole(context.Context, *connect.Request[v1.DefineRoleRequest]) (*connect.Response[v1.DefineRoleResponse], error)
	// ListRoles returns roles available in the tenant.
	ListRoles(context.Context, *connect.Request[v1.AccountAdminServiceListRolesRequest]) (*connect.Response[v1.AccountAdminServiceListRolesResponse], error)
	// AssignRole binds a role to an account.
	AssignRole(context.Context, *connect.Request[v1.AccountAdminServiceAssignRoleRequest]) (*connect.Response[v1.AccountAdminServiceAssignRoleResponse], error)
	// RevokeRole unbinds a role from an account.
	RevokeRole(context.Context, *connect.Request[v1.RevokeRoleRequest]) (*connect.Response[v1.RevokeRoleResponse], error)
	// SetEntitlement creates or replaces an entitlement on an account.
	SetEntitlement(context.Context, *connect.Request[v1.SetEntitlementRequest]) (*connect.Response[v1.SetEntitlementResponse], error)
	// DeleteEntitlement removes an entitlement from an account.
	DeleteEntitlement(context.Context, *connect.Request[v1.DeleteEntitlementRequest]) (*connect.Response[v1.DeleteEntitlementResponse], error)
	// ListEntitlements returns entitlements for an account.
	ListEntitlements(context.Context, *connect.Request[v1.ListEntitlementsRequest]) (*connect.Response[v1.ListEntitlementsResponse], error)
	// CreateTenant creates a new tenant. Super-admin only.
	CreateTenant(context.Context, *connect.Request[v1.CreateTenantRequest]) (*connect.Response[v1.CreateTenantResponse], error)
	// GetTenant retrieves a tenant by id. Super-admin only.
	GetTenant(context.Context, *connect.Request[v1.GetTenantRequest]) (*connect.Response[v1.GetTenantResponse], error)
	// ListTenants enumerates all tenants. Super-admin only (AC-2 evidence).
	ListTenants(context.Context, *connect.Request[v1.ListTenantsRequest]) (*connect.Response[v1.ListTenantsResponse], error)
	// ListPendingRecertifications returns reviews awaiting an admin decision.
	ListPendingRecertifications(context.Context, *connect.Request[v1.AccountAdminServiceListPendingRecertificationsRequest]) (*connect.Response[v1.AccountAdminServiceListPendingRecertificationsResponse], error)
	// SubmitRecertificationDecision records the calling admin's decision on a
	// pending review (approved | revoked | deferred). Reviewer is read from
	// the session context (no field).
	SubmitRecertificationDecision(context.Context, *connect.Request[v1.AccountAdminServiceSubmitRecertificationDecisionRequest]) (*connect.Response[v1.AccountAdminServiceSubmitRecertificationDecisionResponse], error)
	// GetRecertificationHistory returns the historical decision log for one
	// account.
	GetRecertificationHistory(context.Context, *connect.Request[v1.AccountAdminServiceGetRecertificationHistoryRequest]) (*connect.Response[v1.AccountAdminServiceGetRecertificationHistoryResponse], error)
	// ClearAccountMFAFactors removes all MFA factors for an account (e.g.
	// lost YubiKey path — LIFE-04 admin assist). reason is required + emitted
	// as auth.mfa.cleared_by_admin Details.
	ClearAccountMFAFactors(context.Context, *connect.Request[v1.AccountAdminServiceClearAccountMFAFactorsRequest]) (*connect.Response[v1.AccountAdminServiceClearAccountMFAFactorsResponse], error)
}

